import{c as e}from"./app.8935f5f1.js";const o={},i=e('<ul><li><p><strong>docker启动容器失败怎么查看日志</strong></p><ul><li><code>docker logs 容器id</code></li></ul></li><li><p><strong>查看所有容器，包括启动成功与失败的</strong></p><ul><li><code>sudo docker ps -a</code></li></ul></li><li><p><code>docker ps</code> 查看当前正在运行的容器</p></li><li><p><code>docker ps -a</code> 查看所有容器的状态</p></li><li><p><code>docker start/stop id/name</code> 启动/停止某个容器</p></li><li><p><code>docker attach id</code> 进入某个容器(使用exit退出后容器也跟着停止运行)</p></li><li><p><code>docker exec -ti id</code> 启动一个伪终端以交互式的方式进入某个容器（使用exit退出后容器不停止运行）</p></li><li><p><code>docker images</code> 查看本地镜像</p></li><li><p><code>docker rm id/name</code> 删除某个容器</p></li><li><p><code>docker rmi id/name</code> 删除某个镜像</p></li><li><p><code>docker run --name test -ti ubuntu /bin/bash</code></p><ul><li><strong>复制ubuntu容器并且重命名为test且运行，然后以伪终端交互式方式进入容器，运行bash</strong></li></ul></li></ul><ul><li><strong>docker build -t soar/centos:7.1 .</strong> 通过当前目录下的Dockerfile创建一个名为<code>soar/centos:7.1</code>的镜像 <ul><li><strong>docker run -d -p 2222:22 --name test soar/centos:7.1</strong> 以镜像<code>soar/centos:7.1</code>创建名为test的容器，</li><li>并以后台模式运行，并做端口映射到宿主机2222端口，P参数重启容器宿主机端口会发生改变</li></ul></li></ul><h3 id="docker删除镜像" tabindex="-1"><a class="header-anchor" href="#docker删除镜像" aria-hidden="true">#</a> docker删除镜像</h3><h4 id="docker要删除镜像-先要删除依赖它的容器" tabindex="-1"><a class="header-anchor" href="#docker要删除镜像-先要删除依赖它的容器" aria-hidden="true">#</a> docker要删除镜像，先要删除依赖它的容器</h4><ol><li>删除容器</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code>docker <span class="token function">ps</span> <span class="token comment">#查看正在运行的容器</span>\n\ndocker <span class="token function">ps</span> -a <span class="token comment">#查看所有容器</span>\n\ndocker <span class="token function">rm</span> container_id <span class="token comment">#删除容器</span>\n</code></pre></div><ol start="2"><li>删除镜像</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code>docker images //查看镜像\n\ndocker rmi image_id\n</code></pre></div><ol><li>查看镜像 docker images</li><li>删除nginx镜像, docker rmi repid 显示<code>&#39;image is referenced in multiple repositories&#39;</code></li><li>再看控制台中IMAGE ID为sdfsdfdsfsdf的nginx指向两个repository,所以删除失败了</li><li>这时要指定repository和tag删除 <ol><li><code>docker rmi tomcat:tGv2.0.1</code></li></ol></li><li>再次查看镜像，repository为nginx的镜像已被删除</li></ol><h3 id="虚悬镜像" tabindex="-1"><a class="header-anchor" href="#虚悬镜像" aria-hidden="true">#</a> 虚悬镜像</h3><ul><li>镜像既没有仓库名，也没有 标签，均为<code>&lt;none&gt;</code></li></ul><ul><li><p><strong><code>&lt;none&gt; &lt;none&gt;</code> 00285df0df87 5 days ago 342 MB</strong></p></li><li><p>这个镜像原本是有镜像名和标签的，原来为 <code>mongo:3.2</code> ，随着官方镜像维护，发 布了新版本后，重新 <code>docker pull mongo:3.2</code> 时， <code>mongo:3.2</code> 这个镜像名被 转移到了新下载的镜像身上，而旧的镜像上的这个名称则被取消，从而成为了none 。</p></li><li><p>除了 <code>docker pull</code> 可能导致这种情况， <code>docker build</code> 也同样可 以导致这种现象。由于新旧镜像同名，</p></li><li><p>旧镜像名称被取消，从而出现仓库名、标签 均为 的镜像。</p></li><li><p>这类无标签镜像也被称为 <strong>虚悬镜像(dangling image)</strong> ，可 以用下面的命令专门显示这类镜像： <code>docker images -f dangling=true</code> 一般来说，虚悬镜像已经失去了存在的价值，是可以随意删除的，可以用下面的命 令删除。 <code>docker rmi $(docker images -q -f dangling=true)</code></p></li></ul><ul><li>kubernetes <ul><li>pod</li><li>ApiServer</li><li>ClusterIp</li><li>NodePodIp</li><li>loadBlance</li></ul></li></ul>',13);o.render=function(e,o){return i};export{o as default};
